"""
Tool Schema Validator V2 - Enhanced Safety
Addresses issues:
1. Dynamic schema loading from actual tool signatures
2. Case-insensitive parameter matching
3. Similarity-based suggestions for typos
4. Safe fallback modes
"""

from typing import Dict, List, Any, Optional, Tuple
import difflib


class ToolSchemaValidatorV2:
    """
    Enhanced validator with safety mechanisms:
    - Loads schemas dynamically from tool_manager
    - Fuzzy matching for typos
    - Whitelist mode (warn only, don't block)
    - Case-insensitive matching
    """

    def __init__(self, tool_manager=None, strict_mode: bool = False):
        """
        Initialize validator.

        Args:
            tool_manager: Optional tool manager to load schemas from
            strict_mode: If False, only warns about issues. If True, blocks execution.
        """
        self.strict_mode = strict_mode
        self.tool_schemas = {}
        self.rejection_stats = {}

        # Try to load schemas dynamically if tool_manager provided
        if tool_manager:
            self._load_schemas_from_tool_manager(tool_manager)
        else:
            # Fallback to static schemas
            self._load_static_schemas()

    def _load_schemas_from_tool_manager(self, tool_manager):
        """Dynamically extract schemas from actual tool signatures"""
        try:
            # Get tool registry from tool_manager
            if hasattr(tool_manager, 'tools'):
                for tool_name, tool_func in tool_manager.tools.items():
                    # Extract parameters from function signature
                    import inspect
                    sig = inspect.signature(tool_func)

                    required = []
                    optional = []
                    all_params = set()

                    for param_name, param in sig.parameters.items():
                        if param_name == 'self':
                            continue

                        all_params.add(param_name)

                        if param.default == inspect.Parameter.empty:
                            required.append(param_name)
                        else:
                            optional.append(param_name)

                    self.tool_schemas[tool_name] = {
                        'required': required,
                        'optional': optional,
                        'all_params': all_params
                    }
        except Exception:
            # If dynamic loading fails, use static fallback
            self._load_static_schemas()

    def _load_static_schemas(self):
        """Fallback static schemas"""
        self.tool_schemas = {
            'file_read': {
                'required': ['file_path'],
                'optional': ['encoding', 'max_lines', 'start_line'],  # Extended
                'all_params': {'file_path', 'encoding', 'max_lines', 'start_line'}
            },
            'file_write': {
                'required': ['file_path', 'content'],
                'optional': ['encoding', 'mode', 'create_dirs'],
                'all_params': {'file_path', 'content', 'encoding', 'mode', 'create_dirs'}
            },
            'file_edit': {
                'required': ['file_path', 'old_content', 'new_content'],
                'optional': ['encoding', 'count'],
                'all_params': {'file_path', 'old_content', 'new_content', 'encoding', 'count'}
            },
            'bash_execute': {
                'required': ['command'],
                'optional': ['timeout', 'check', 'cwd', 'env', 'shell'],
                'all_params': {'command', 'timeout', 'check', 'cwd', 'env', 'shell'}
            },
            'grep_search': {
                'required': ['pattern'],
                'optional': ['path', 'file_pattern', 'context_lines', 'ignore_case', 'recursive'],
                'all_params': {'pattern', 'path', 'file_pattern', 'context_lines', 'ignore_case', 'recursive'}
            },
            'git_operations': {
                'required': ['operation'],
                'optional': ['args', 'path', 'message'],
                'all_params': {'operation', 'args', 'path', 'message'}
            },
            'file_search': {
                'required': [],
                'optional': ['pattern', 'path', 'file_type', 'max_results', 'recursive'],
                'all_params': {'pattern', 'path', 'file_type', 'max_results', 'recursive'}
            },
        }

    def validate_tool_call(self, tool_name: str, args: Dict[str, Any]) -> Tuple[bool, List[str], Dict[str, Any]]:
        """
        Validate tool call with enhanced safety.

        Args:
            tool_name: Tool name
            args: Tool arguments

        Returns:
            (is_valid, warnings, filtered_args)
        """
        warnings = []
        filtered_args = {}

        # Unknown tool - use permissive mode
        if tool_name not in self.tool_schemas:
            if self.strict_mode:
                return False, [f"Unknown tool '{tool_name}' - strict mode blocks execution"], {}
            else:
                return True, [f"Unknown tool '{tool_name}' - validation skipped (permissive mode)"], args

        schema = self.tool_schemas[tool_name]

        # Check required parameters with fuzzy matching
        missing_required = []
        for required_param in schema['required']:
            # Case-insensitive check
            found = False
            for provided_param in args.keys():
                if provided_param.lower() == required_param.lower():
                    filtered_args[required_param] = args[provided_param]  # Normalize to correct case
                    found = True
                    break

            if not found:
                # Try fuzzy match suggestion
                suggestion = self._find_closest_match(required_param, args.keys())
                if suggestion:
                    warnings.append(f"Missing required '{required_param}' - did you mean '{suggestion}'?")
                else:
                    missing_required.append(required_param)

        if missing_required:
            warnings.append(f"Missing required parameters: {', '.join(missing_required)}")
            if self.strict_mode:
                return False, warnings, {}

        # Filter parameters with fuzzy matching
        for param_name, param_value in args.items():
            # Case-insensitive exact match
            normalized_name = None
            for valid_param in schema['all_params']:
                if param_name.lower() == valid_param.lower():
                    normalized_name = valid_param
                    break

            if normalized_name:
                filtered_args[normalized_name] = param_value
            else:
                # Not exact match - try fuzzy
                suggestion = self._find_closest_match(param_name, schema['all_params'])
                if suggestion and self._similarity_score(param_name, suggestion) > 0.7:
                    warnings.append(f"Auto-corrected '{param_name}' → '{suggestion}' (typo?)")
                    filtered_args[suggestion] = param_value
                else:
                    # Likely hallucination
                    warnings.append(f"Removed unknown parameter: '{param_name}' (not in schema)")
                    self._track_rejection(tool_name, param_name)

        return True, warnings, filtered_args

    def _find_closest_match(self, target: str, candidates: List[str]) -> Optional[str]:
        """Find closest matching parameter name"""
        if not candidates:
            return None
        matches = difflib.get_close_matches(target, candidates, n=1, cutoff=0.6)
        return matches[0] if matches else None

    def _similarity_score(self, a: str, b: str) -> float:
        """Calculate similarity between two strings (0.0-1.0)"""
        return difflib.SequenceMatcher(None, a.lower(), b.lower()).ratio()

    def _track_rejection(self, tool_name: str, param_name: str):
        """Track rejections for analysis"""
        key = f"{tool_name}.{param_name}"
        self.rejection_stats[key] = self.rejection_stats.get(key, 0) + 1


# Global instance - permissive mode by default
tool_schema_validator_v2 = ToolSchemaValidatorV2(strict_mode=False)
